Migrates an existing pre-commit configuration to an hk.pkl file.

```APIDOC
## CLI Command: hk migrate pre-commit

### Description
Migrates from pre-commit to hk.

### Usage
`hk migrate pre-commit [FLAGS]`

### Parameters
#### Flags
- **-c, --config** (string) - Optional - Path to .pre-commit-config.yaml (Default: .pre-commit-config.yaml)
- **-f, --force** (boolean) - Optional - Overwrite existing hk.pkl file
- **-o, --output** (string) - Optional - Output path for hk.pkl (Default: hk.pkl)
- **--hk-pkl-root** (string) - Optional - Root path for hk pkl files. If specified, will use {root}/Config.pkl and {root}/Builtins.pkl
```

--------------------------------

### Define hk configuration with hooks and linters

Source: https://context7.com/jdx/hk/llms.txt

Configures global settings and reusable linter steps within an hk.pkl file.

```pkl
amends "package://github.com/jdx/hk/releases/download/v1.43.0/hk@1.43.0#/Config.pkl"
import "package://github.com/jdx/hk/releases/download/v1.43.0/hk@1.43.0#/Builtins.pkl"

// Global environment variables
env {
    ["NODE_ENV"] = "production"
}

// Global exclude patterns
exclude = List("node_modules", "dist", "build")

// Number of parallel jobs (0 = auto-detect)
jobs = 0

// Abort on first failure
fail_fast = true

// Define reusable linter configurations
local linters = new Mapping<String, Step> {
    // Manual linter definition
    ["eslint"] {
        glob = List("*.js", "*.ts", "*.tsx")
        check = "eslint {{files}}"
        fix = "eslint --fix {{files}}"
        batch = true  // Enable parallel batching
    }
    // Use builtin with overrides
    ["prettier"] = (Builtins.prettier) {
        glob = List("*.js", "*.ts", "*.json", "*.md")
    }
    // Use builtin as-is
    ["cargo_fmt"] = Builtins.cargo_fmt
}

hooks {
    ["pre-commit"] {
        fix = true        // Run fix commands
        stash = "git"     // Stash unstaged changes
        stage = true      // Auto-stage fixed files
        steps = linters
    }
    ["pre-push"] {
        // Check-only for pre-push (no modifications)
        steps = linters
    }
    // Special hooks for hk check/fix commands
    ["check"] {
        steps = linters
    }
    ["fix"] {
        fix = true
        steps = linters
    }
}
```

--------------------------------

### Step Groups in HK Hooks

Source: https://context7.com/jdx/hk/llms.txt

Group steps within HK hooks to control execution order and dependencies. Groups allow steps to run in parallel within the group, and groups execute sequentially.

```pkl
hooks {
    ["pre-commit"] {
        steps {
            // Build group runs first, all steps in parallel
            ["build"] = new Group {
                steps {
                    ["typescript"] {
                        fix = "tsc -b"
                    }
                    ["rust"] {
                        fix = "cargo build"
                    }
                }
            }
            // Lint group runs after build completes
            ["lint"] = new Group {
                steps {
                    ["prettier"] = Builtins.prettier
                    ["eslint"] = Builtins.eslint
                }
            }
        }
    }
}
```

--------------------------------

### Environment Variables for HK

Source: https://context7.com/jdx/hk/llms.txt

Control HK behavior using environment variables. This method allows for dynamic configuration without modifying config files.

```bash
# Set number of parallel jobs
HK_JOBS=8 hk check

# Disable fix mode (check only)
HK_FIX=0 hk run pre-commit

# Enable specific profiles
HK_PROFILE=slow,ci hk check

# Skip specific steps
HK_SKIP_STEPS=lint,test hk run pre-commit

# Skip entire hooks
HK_SKIP_HOOK=pre-commit git commit -m "message"

# Set stash method
HK_STASH=none hk fix  # Fastest, no stashing
HK_STASH=patch-file hk fix  # Fast, uses patch file
HK_STASH=git hk fix  # Standard git stash

# Configure logging
HK_LOG=debug hk check
HK_LOG_FILE=/tmp/hk.log hk check

# Use built-in pkl evaluator instead of pkl CLI
HK_PKL_BACKEND=pklr hk check

# Enable mise integration by default
HK_MISE=1 hk install

# Abort on first failure
HK_FAIL_FAST=1 hk check

# Output timing report
HK_TIMING_JSON=/tmp/timing.json hk check

# Use custom config file
HK_FILE=custom-hk.pkl hk check

# Exclude patterns
HK_EXCLUDE="node_modules,dist,**/*.min.js" hk check
```

